function formatCurrency(val) {
  if (val == null) return '--';
  return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', minimumFractionDigits: 2 }).format(val);
}

function Sparkline({ data, color, width = 200, height = 40 }) {
  if (!data?.length || data.length < 2) return null;
  const clean = data.filter(v => v != null && isFinite(v));
  if (clean.length < 2) return null;
  const min = Math.min(...clean);
  const max = Math.max(...clean);
  const range = max - min || 1;
  const points = clean
    .map((v, i) => `${(i / (clean.length - 1)) * width},${height - ((v - min) / range) * (height - 4) - 2}`)
    .join(' ');
  const lastVal = clean[clean.length - 1];
  const firstVal = clean[0];
  const trend = lastVal >= firstVal ? color : C.red;
  return (
    <svg width={width} height={height} style={{ display: 'block' }}>
      <defs>
        <linearGradient id={`grad-${color.replace('#', '')}`} x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor={trend} stopOpacity="0.15" />
          <stop offset="100%" stopColor={trend} stopOpacity="0" />
        </linearGradient>
      </defs>
      <polygon
        points={`0,${height} ${points} ${width},${height}`}
        fill={`url(#grad-${color.replace('#', '')})`}
      />
      <polyline points={points} fill="none" stroke={trend} strokeWidth="1.5" />
      <circle
        cx={width}
        cy={height - ((lastVal - min) / range) * (height - 4) - 2}
        r="2.5" fill={trend}
      />
    </svg>
  );
}

function ModeBadge({ mode }) {
  const modeColors = { LIVE: C.green, PAPER: C.amber, STOPPED: C.red, DISABLED: C.textSecondary, DRY_RUN: C.amber };
  const color = modeColors[(mode || '').toUpperCase()] || C.textSecondary;
  const upper = (mode || 'unknown').toUpperCase();
  const isLive = upper === 'LIVE';
  const isPaper = upper === 'PAPER' || upper === 'DRY_RUN';
  return (
    <span
      className={s.modeBadge}
      style={{
        color: upper === 'DISABLED' ? C.textSecondary : isLive ? '#000' : color,
        background: upper === 'DISABLED' ? `${C.textSecondary}22` : isLive ? color : `${color}18`,
        border: `2px solid ${color}`,
        boxShadow: isLive ? `0 0 12px ${color}40` : isPaper ? `0 0 8px ${color}25` : 'none',
      }}
    >
      <span
        className={`${s.modeDot} ${isLive || isPaper ? s.modeDotPulse : ''}`}
        style={{
          background: isLive ? '#000' : color,
          boxShadow: isLive ? 'none' : `0 0 6px ${color}`,
        }}
      />
      {upper}
    </span>
  );
}

function RiskTierBadge({ tier, reasons }) {
  const tierColors = { LOW: C.green, MED: C.amber, HIGH: C.red };
  const color = tierColors[(tier || '').toUpperCase()] || C.textSecondary;
  const displayTier = tier || 'N/A';
  const tooltip = reasons?.length ? reasons.join('\n') : 'No risk data';
  return (
    <span
      title={tooltip}
      className={s.riskBadge}
      style={{
        color, background: `${color}15`, border: `1px solid ${color}25`,
      }}
    >
      RISK: {displayTier}
    </span>
  );
}

function HeartbeatBadge({ lastHeartbeat, status }) {
  if (!lastHeartbeat) {
    return (
      <span className={s.heartbeatBadge} style={{ color: C.textSecondary, background: `${C.textSecondary}12`, border: `1px solid ${C.textSecondary}20` }}>
        <span className={s.heartbeatDot} style={{ background: C.textSecondary }} />
        NO DATA
      </span>
    );
  }
  const now = Date.now();
  const hbTime = new Date(lastHeartbeat).getTime();
  const ageSec = Math.max(0, Math.floor((now - hbTime) / 1000));
  let color, label, glow;
  if (ageSec < 60) {
    color = C.green; label = `${ageSec}s ago`; glow = true;
  } else if (ageSec < 300) {
    const ageMin = Math.floor(ageSec / 60);
    color = C.amber; label = `${ageMin}m ago`; glow = false;
  } else {
    const ageMin = Math.floor(ageSec / 60);
    color = C.red; label = ageMin >= 60 ? `${Math.floor(ageMin / 60)}h ago` : `${ageMin}m ago`; glow = false;
  }
  return (
    <span className={s.heartbeatBadge} style={{ color, background: `${color}12`, border: `1px solid ${color}25` }} title={`Last heartbeat: ${new Date(lastHeartbeat).toLocaleString()}`}>
      <span className={`${s.heartbeatDot} ${glow ? s.heartbeatDotPulse : ''}`} style={{ background: color, boxShadow: glow ? `0 0 6px ${color}` : 'none' }} />
      {label}
    </span>
  );
}

function RiskBudgetBar({ used, total, label }) {
  const pct = total > 0 ? Math.min(100, (used / total) * 100) : 0;
  let barColor = C.green;
  if (pct > 80) barColor = C.red;
  else if (pct > 50) barColor = C.amber;

  return (
    <div className={s.riskBudgetBarWrap}>
      <div className={s.riskBudgetBarHeader}>
        <span className={s.riskBudgetBarLabel}>{label || 'Risk Budget'}</span>
        <span className={s.riskBudgetBarPct} style={{ color: barColor }}>{pct.toFixed(0)}%</span>
      </div>
      <div className={s.riskBudgetBarTrack}>
        <div className={s.riskBudgetBarFill} style={{ width: `${pct}%`, background: barColor }} />
      </div>
    </div>
  );
}

function QuickActions({ bot, onModeChange, saving }) {
  const botKey = bot.bot_name || bot.name?.toLowerCase();
  const currentMode = (bot.mode || 'unknown').toUpperCase();
  const isRunning = currentMode === 'LIVE' || currentMode === 'PAPER' || currentMode === 'DRY_RUN';

  const handlePause = () => onModeChange(botKey, 'DRY_RUN');
  const handleResume = () => onModeChange(botKey, 'LIVE');

  return (
    <div className={s.quickActions}>
      {isRunning ? (
        <button
          onClick={handlePause}
          disabled={saving}
          className={s.quickActionBtn}
          style={{ color: C.amber, borderColor: `${C.amber}40` }}
          title="Pause bot (switch to DRY_RUN)"
        >
          Pause
        </button>
      ) : (
        <button
          onClick={handleResume}
          disabled={saving}
          className={s.quickActionBtn}
          style={{ color: C.green, borderColor: `${C.green}40` }}
          title="Resume bot (switch to LIVE)"
        >
          Resume
        </button>
      )}
    </div>
  );
}

